import { useState, useRef } from 'react';
import { 
  Type, Image as ImageIcon, Sparkles, Shapes, 
  Layers, Palette, Trash2, Move, LayoutGrid,
  Search, Plus, Crown, MousePointer2
} from 'lucide-react';

// --- NOUVELLES CATÉGORIES D'ÉLÉMENTS ---
const ASSET_CATEGORIES = [
  { id: 'stickers', label: 'Stickers', icon: Sparkles, color: '#FFD700' },
  { id: 'illustrations', label: 'Illustrations', icon: LayoutGrid, color: '#FF6B6B' },
  { id: 'typography', label: 'Textes Stylés', icon: Type, color: '#4ECDC4' },
  { id: 'shapes', label: 'Formes', icon: Shapes, color: '#45B7D1' },
  { id: 'uploads', label: 'Mes Photos', icon: ImageIcon, color: '#017BFE' },
];

export default function PersonnalisationPro() {
  const [activeTab, setActiveTab] = useState('stickers');
  const [selectedElement, setSelectedElement] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Simulation des mockups réels (Photos de haute qualité avec zones d'ombre)
  const currentMockup = "/mockups/tshirt-white-flat-lay.png"; 

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F0F2F5', overflow: 'hidden' }}>

      {/* 1. BARRE D'OUTILS (Style Figma/Canva) */}
      <div style={{ width: 80, background: '#1A1A1A', display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '20px 0', gap: 20 }}>
        <div style={{ color: 'white', marginBottom: 20 }}>
            <img src="/logo-icon.png" width={32} style={{ filter: 'brightness(0) invert(1)' }} />
        </div>
        {ASSET_CATEGORIES.map(cat => (
          <button 
            key={cat.id}
            onClick={() => setActiveTab(cat.id)}
            style={{ 
              background: activeTab === cat.id ? '#333' : 'transparent',
              border: 'none', color: activeTab === cat.id ? cat.color : '#888',
              padding: '12px', borderRadius: 12, cursor: 'pointer', transition: '0.2s',
              position: 'relative'
            }}
          >
            <cat.icon size={24} />
            {activeTab === cat.id && <div style={{ position: 'absolute', right: 0, top: '25%', height: '50%', width: 3, background: cat.color, borderRadius: '4px 0 0 4px' }} />}
          </button>
        ))}
      </div>

      {/* 2. PANNEAU LATÉRAL DES ÉLÉMENTS (C'est ici qu'on ajoute stickers, illustrations...) */}
      <div style={{ width: 320, background: 'white', borderRight: '1px solid #E2E8F0', padding: 20, display: 'flex', flexDirection: 'column' }}>
        <h2 style={{ fontSize: 18, fontWeight: 900, marginBottom: 16, textTransform: 'capitalize' }}>{activeTab}</h2>

        {/* Barre de recherche interne */}
        <div style={{ position: 'relative', marginBottom: 20 }}>
            <Search size={14} style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#94A3B8' }} />
            <input 
                placeholder={`Rechercher un ${activeTab}...`} 
                style={{ width: '100%', padding: '10px 10px 10px 36px', borderRadius: 10, border: '1px solid #E2E8F0', outline: 'none', fontSize: 13 }}
            />
        </div>

        {/* Grille d'éléments (Alimentée par l'Admin) */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, overflowY: 'auto' }}>
            {/* Simulation d'éléments venant de la DB */}
            {Array.from({ length: 12 }).map((_, i) => (
                <div 
                    key={i}
                    style={{ 
                        aspectRatio: '1', background: '#F8FAFC', borderRadius: 12, 
                        cursor: 'pointer', border: '2px solid transparent', transition: '0.2s',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        position: 'relative', overflow: 'hidden'
                    }}
                    onMouseEnter={e => e.currentTarget.style.borderColor = '#017BFE'}
                    onMouseLeave={e => e.currentTarget.style.borderColor = 'transparent'}
                >
                    <img src={`/assets/${activeTab}/${i}.png`} style={{ maxWidth: '80%' }} />
                    {i % 4 === 0 && <Crown size={12} style={{ position: 'absolute', top: 8, right: 8, color: '#E6B95E' }} />}
                </div>
            ))}
        </div>
      </div>

      {/* 3. CANVAS CENTRAL (Zone de Design) */}
      <div style={{ flex: 1, position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 40 }}>

        {/* Contrôles de vue (Floating) */}
        <div style={{ position: 'absolute', top: 20, left: '50%', transform: 'translateX(-50%)', background: 'white', padding: '6px 20px', borderRadius: 30, display: 'flex', gap: 20, boxShadow: '0 4px 12px rgba(0,0,0,0.05)', zIndex: 10 }}>
            <button style={{ border: 'none', background: 'none', fontWeight: 700, fontSize: 12, cursor: 'pointer', color: '#017BFE' }}>FACE</button>
            <button style={{ border: 'none', background: 'none', fontWeight: 700, fontSize: 12, cursor: 'pointer', color: '#888' }}>DOS</button>
            <button style={{ border: 'none', background: 'none', fontWeight: 700, fontSize: 12, cursor: 'pointer', color: '#888' }}>MANCHE</button>
        </div>

        {/* Le Mockup Réel (Image de fond haute résolution) */}
        <div style={{ position: 'relative', width: '100%', maxWidth: 700, aspectRatio: '4/5' }}>
            <img 
                src={currentMockup} 
                style={{ width: '100%', height: '100%', objectFit: 'contain' }} 
                alt="Product Mockup" 
            />

            {/* Zone de personnalisation (Invisible mais limite les éléments) */}
            <div style={{ 
                position: 'absolute', top: '22%', left: '28%', width: '44%', height: '50%',
                border: '1px dashed rgba(1, 123, 254, 0.3)', borderRadius: 4,
                display: 'flex', alignItems: 'center', justifyContent: 'center'
            }}>
                {/* Ici les éléments draggables (utilisant react-rnd ou fabric.js) */}
                <div style={{ color: '#017BFE', fontSize: 10, opacity: 0.5, position: 'absolute', bottom: -20 }}>Zone d'impression maximum</div>
            </div>
        </div>
      </div>

      {/* 4. PANNEAU DE PROPRIÉTÉS (Style Figma - Apparaît si un élément est sélectionné) */}
      <div style={{ width: 280, background: 'white', borderLeft: '1px solid #E2E8F0', padding: 24 }}>
        <h3 style={{ fontSize: 14, fontWeight: 900, marginBottom: 24, textTransform: 'uppercase', letterSpacing: '1px' }}>Propriétés</h3>

        {selectedElement ? (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
                {/* Couleurs (Si SVG ou Forme) */}
                <div>
                    <p style={{ fontSize: 12, fontWeight: 700, color: '#64748B', marginBottom: 12 }}>COULEUR</p>
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                        {['#000', '#FFF', '#017BFE', '#FF4757', '#2ED573'].map(c => (
                            <div key={c} style={{ width: 28, height: 28, borderRadius: '50%', background: c, border: '1px solid #E2E8F0', cursor: 'pointer' }} />
                        ))}
                        <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'linear-gradient(45deg, red, blue)', border: '1px solid #E2E8F0', cursor: 'pointer' }} />
                    </div>
                </div>

                {/* Dimensions / Position */}
                <div>
                    <p style={{ fontSize: 12, fontWeight: 700, color: '#64748B', marginBottom: 12 }}>TRANSFORMER</p>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
                        <div style={{ background: '#F8FAFC', padding: 8, borderRadius: 8 }}>
                            <span style={{ fontSize: 10, color: '#94A3B8' }}>L</span>
                            <input type="number" defaultValue={200} style={{ border: 'none', background: 'none', width: '100%', fontWeight: 700, fontSize: 13, outline: 'none' }} />
                        </div>
                        <div style={{ background: '#F8FAFC', padding: 8, borderRadius: 8 }}>
                            <span style={{ fontSize: 10, color: '#94A3B8' }}>H</span>
                            <input type="number" defaultValue={200} style={{ border: 'none', background: 'none', width: '100%', fontWeight: 700, fontSize: 13, outline: 'none' }} />
                        </div>
                    </div>
                </div>

                {/* Actions Rapides */}
                <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
                    <button style={{ flex: 1, padding: '10px', borderRadius: 10, border: '1px solid #E2E8F0', background: 'white', cursor: 'pointer' }}><Trash2 size={16} color="#EF4444" /></button>
                    <button style={{ flex: 1, padding: '10px', borderRadius: 10, border: '1px solid #E2E8F0', background: 'white', cursor: 'pointer' }}><Layers size={16} /></button>
                </div>
            </div>
        ) : (
            <div style={{ textAlign: 'center', marginTop: 100, color: '#94A3B8' }}>
                <MousePointer2 size={32} style={{ marginBottom: 16, opacity: 0.2, margin: '0 auto' }} />
                <p style={{ fontSize: 12, fontWeight: 500 }}>Sélectionnez un élément pour le modifier</p>
            </div>
        )}
      </div>
    </div>
  );
}
